const job = $input.first().json;
const event = $input.all()[0].json.body || {};

const oldStatus = event.old_status || event.oldStatus;
const newStatus = event.new_status || event.newStatus || job.status;

const statusEmojis = {
  'pending': '🕐',
  'assigned': '🔗',
  'in_progress': '🛠️',
  'completed': '✅',
  'cancelled': '❌',
  'on_hold': '⏸️',
  'rescheduled': '📅'
};

const statusMessages = {
  'assigned': `Your job has been assigned to a worker! They'll be in touch shortly.`,
  'in_progress': `Great news! Work has started on your job.`,
  'completed': `Your job has been completed! We'd love to hear your feedback.`,
  'cancelled': `Your job has been cancelled. If this was a mistake, please contact us.`,
  'on_hold': `Your job has been temporarily put on hold. We'll update you when it resumes.`,
  'rescheduled': `Your job has been rescheduled. Please check the new date/time.`
};

const emoji = statusEmojis[newStatus] || '📋';
const message = statusMessages[newStatus] || `Your job status has been updated to: ${newStatus}`;

let telegramMsg = `${emoji} *Job Status Update*\n\n`;
telegramMsg += `🔧 Job #${job.id}: ${job.title || job.description || 'Service Job'}\n`;
telegramMsg += `📊 Status: *${oldStatus || '?'}* → *${newStatus}*\n\n`;
telegramMsg += `${message}\n`;

if (job.worker_name) {
  telegramMsg += `\n👷 Assigned Worker: ${job.worker_name}`;
}
if (job.scheduled_date) {
  telegramMsg += `\n📅 Scheduled: ${job.scheduled_date}`;
}
if (job.estimated_completion) {
  telegramMsg += `\n⏱️ Est. Completion: ${job.estimated_completion}`;
}

telegramMsg += `\n\n💬 Questions? Reply to this message or contact support.`;

return {
  jobId: job.id,
  clientId: job.client_id,
  clientName: job.client_name,
  clientTelegramId: job.client_telegram_id,
  oldStatus: oldStatus,
  newStatus: newStatus,
  telegramMessage: telegramMsg,
  isCompleted: newStatus === 'completed',
  isCancelled: newStatus === 'cancelled'
};
